using System.Collections.Generic;

namespace CISCSections
{
    public enum SectionType { WShape, SShape, Channel, Angle, HSSRectangular, HSSCircular }
    public enum ViewType   { CrossSection, SideView, TopView }

    public class SectionProperties
    {
        public string     Name { get; set; }
        public SectionType Type { get; set; }

        // W / C shapes
        public double d  { get; set; }   // overall depth (mm)
        public double bf { get; set; }   // flange width (mm)
        public double tf { get; set; }   // flange thickness (mm)
        public double tw { get; set; }   // web thickness (mm)

        // HSS Rectangular
        public double H { get; set; }    // height (mm)
        public double B { get; set; }    // width  (mm)

        // shared wall / leg thickness
        public double t { get; set; }

        // HSS Circular
        public double D { get; set; }    // outer diameter (mm)

        // L Angle legs
        public double Hleg { get; set; }
        public double Vleg { get; set; }

        public override string ToString() => Name;
    }

